INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6009, 0, "drama_talk_doubt_loop", "", 3, 1, "drama_talk_doubt_in", 6, "", 129911, 0.2);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6010, 0, 0, "", 21, "", "vo_minigame_1013_top_talk_6_001", 6, "", "vo_minigame_1013", "");
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6011, 6, 1, 0.8, 11, 0, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 6, 0, 129911, 0);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6012, "", "", "", 91, "", "", 6, "", 0, "");
