INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6014, 0, "drama_talk_surprise_loop_shy", "", 3, 1, "drama_talk_surprise_in_shy", 6, "", 129811, 0.2);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6015, 0, 0, "", 21, "", "vo_minigame_1013_top_talk_6_002", 6, "", "vo_minigame_1013", "");
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6016, 9, 1, 0.3, 11, 0, "いやいや何でもない！\nあたしは別に変なこと\n考えてないからな！\nそれより訓練だっ！", 6, 0, 129811, 0);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6017, "", "", "", 91, "", "", 6, "", 0, "");
