INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7005, 0, 0, "", 21, "", "vo_minigame_1013_top_talk_7_000", 7, "", "vo_minigame_1013", "");
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7006, 6, 1, 0.3, 11, 0, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 7, 0, 129911, 0);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7007, "", "", "", 91, "", "", 7, "", 0, "");
