INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7010, 0, 0, "", 21, "", "vo_minigame_1013_top_talk_7_001", 7, "", "vo_minigame_1013", "");
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7011, 6, 1, 0, 11, 0, "エリコ班の急成長は\n騎士団の中でも話題に\nなってたからな\nホントすげえ奴等だよ", 7, 0, 129811, 0);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7012, "", "", "", 91, "", "", 7, "", 0, "");
