INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7014, 1, "", "", 3, "", "drama_talk_thinking", 7, "", 129911, 0.2);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7015, 0, 0, "", 21, "", "vo_minigame_1013_top_talk_7_002", 7, "", "vo_minigame_1013", "");
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7016, 6, 1, 0.5, 11, 0, "彼らが私に逆らわずに\n努力したからこそ、\n得たものもありますし\n…感謝しておきますわ", 7, 0, 129911, 0);
