INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (8006, 7, 1, 0.3, 11, 0, "マコト班のみんなも、\nしっかり頑張って\nくれてるみたいだ\n教官としても嬉しいぜ", 8, 0, 129811, 0);
